import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/extension-view.BUCve89_.js";const s=JSON.parse(`{"title":"Impostare VS Code","description":"Una guida passo per passo su come impostare Visual Studio Code per creare mod usando Fabric.","frontmatter":{"title":"Impostare VS Code","description":"Una guida passo per passo su come impostare Visual Studio Code per creare mod usando Fabric.","authors":["dicedpixels"],"prev":{"text":"Impostare il Tuo IDE","link":"../setting-up"},"next":{"text":"Aprire un progetto in VS Code","link":"./opening-a-project"},"resources":{"https://code.visualstudio.com/":"Scarica Visual Studio Code","https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack":"Extension Pack for Java - VS Marketplace"},"files":[]},"headers":[],"relativePath":"it_it/develop/getting-started/vscode/setting-up.md","filePath":"translated/it_it/develop/getting-started/vscode/setting-up.md","lastUpdated":1774518827000}`);var c={name:`it_it/develop/getting-started/vscode/setting-up.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Impostare VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Impostare VS Code”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><p>Anche se è tecnicamente possibile sviluppare mod in Visual Studio Code, lo sconsigliamo. Dovresti usare <a href="./../intellij-idea/setting-up">IntelliJ IDEA</a>, che fornisce tooling dedicato per Java, funzioni avanzate, e plugin utili creati dalla comunità, tra cui <strong>Minecraft Development</strong>.</p></div><div class="info custom-block"><p class="custom-block-title">PREREQUISITI</p><p>Assicurati di aver già <a href="./../setting-up#install-jdk-21">installato un JDK</a>.</p></div><h2 id="installation" tabindex="-1">Installazione <a class="header-anchor" href="#installation" aria-label="Permalink to “Installazione”">​</a></h2><p>Puoi scaricare Visual Studio Code da <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">code.visualstudio.com</a> o tramite il tuo gestore di pacchetti preferito.</p><p><img src="/assets/develop/getting-started/vscode/download.png" alt="Pagina da cui scaricare Visual Studio Code" loading="lazy"></p><h2 id="prerequisites" tabindex="-1">Prerequisiti <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisiti”">​</a></h2><p>Visual Studio Code non include il supporto del linguaggio Java appena installato. Tuttavia, Microsoft redige un pacchetto di estensioni conveniente, perché contiene tutto il necessario per attivare il supporto di Java.</p><p>Puoi installare questo pacchetto dal <a href="https://marketplace.visualstudio.com/items?itemName=vscjava.vscode-java-pack" target="_blank" rel="noreferrer">Marketplace di Visual Studio</a>.</p><p><img src="/assets/develop/getting-started/vscode/extension.png" alt="Pacchetto di estensioni per Java" loading="lazy"></p><p>Oppure, se sei in Visual Studio Code, dalla vista Extensions.</p><p><img src="/assets/develop/getting-started/vscode/extension-view.png" alt="Pacchetto di estensioni per Java, nella vista Extensions di VS Code" loading="lazy"></p><p>L&#39;estensione <strong>Language Support for Java</strong> mostrerà all&#39;avvio una schermata per configurare un JDK. Se non l&#39;hai ancora fatto, configuralo.</p>`,13)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};